import React, { useEffect, useState } from 'react';

export default function ReportsTab() {
  const [reports, setReports] = useState([]);
  const [file, setFile] = useState(null);
  const token = localStorage.getItem('token');

  useEffect(() => { fetchReports(); }, []);

  async function fetchReports() {
    const res = await fetch('http://localhost:5000/api/reports', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setReports(data);
  }

  async function upload(e) {
    e.preventDefault();
    if (!file) return;
    const fd = new FormData();
    fd.append('report', file);
    await fetch('http://localhost:5000/api/reports', { method: 'POST', headers: { Authorization: `Bearer ${token}` }, body: fd });
    setFile(null);
    fetchReports();
  }

  return (
    <div>
      <h3>Upload Report</h3>
      <form onSubmit={upload}>
        <div className="form-row">
          <input type="file" onChange={e=>setFile(e.target.files[0])} />
        </div>
        <div><button type="submit">Upload</button></div>
      </form>

      <h3 style={{ marginTop: 16 }}>Your Reports</h3>
      {reports.map(r => (
        <div key={r._id} className="list-item">
          <a href={`http://localhost:5000/uploads/${r.filename}`} target="_blank" rel="noreferrer">{r.originalname}</a>
          <div>{new Date(r.createdAt).toLocaleString()}</div>
        </div>
      ))}
    </div>
  );
}
